Use a greedy best-insertion approach that evaluates all feasible assign slots for each order and selects the minimum marginal cost increase, with fallback to seed insertion if no valid slot exists.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestAssignIdx := -1
		bestCostIncrease := math.MaxFloat64
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		for assignIdx := 0; assignIdx < MAXASSIGNS; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]
			oldCost := assign.Cost
			if oldCost < 0 {
				continue
			}
			added := assign.AddShip(shipID, ori, des)
			if !added {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}
			costIncrease := newCost - oldCost
			if costIncrease < bestCostIncrease {
				bestCostIncrease = costIncrease
				bestAssignIdx = assignIdx
			}
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		if bestAssignIdx >= 0 {
			selectedAssign := &dispatch.Assigns[bestAssignIdx]
			selectedAssign.AddShip(shipID, ori, des)
			selectedAssign.GenRoute()
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			fallbackInserted := false
			for assignIdx := 0; assignIdx < MAXASSIGNS; assignIdx++ {
				assign := &dispatch.Assigns[assignIdx]
				if assignIdx >= dispatch.AssignsLen {
					added := assign.AddShip(shipID, ori, des)
					if added {
						assign.GenRoute()
						if assign.Cost >= 0 {
							dispatch.AssignsLen++
							fallbackInserted = true
